import React, { useEffect, useMemo, useRef, useState } from 'react';
import ProductForm from './ProductForm';
import { getProductTypes, getProducts, createProduct, updateProduct, deleteProduct, Product, ProductType } from '../services/api';

const filterOptions = ['Active Products', 'Inactive Products'];
const columnFilterOptions = [
  'Contains',
  'Does not contain',
  'Equals',
  'Does not equal',
  'Begins with',
  'Ends with',
  'Blank',
  'Not blank',
] as const;

type ColumnField = 'name' | 'productType' | 'manufacturer' | 'partNo' | 'cost' | 'active' | 'description';
type ColumnFilterOperator = (typeof columnFilterOptions)[number];
type ColumnFilter = {
  operator: ColumnFilterOperator;
  value: string;
};

const allColumns = [
  { field: 'name' as ColumnField, label: 'Name' },
  { field: 'productType' as ColumnField, label: 'Product Type' },
  { field: 'manufacturer' as ColumnField, label: 'Manufacturer' },
  { field: 'partNo' as ColumnField, label: 'Part No' },
  { field: 'cost' as ColumnField, label: 'Cost' },
  { field: 'active' as ColumnField, label: 'Active' },
  { field: 'description' as ColumnField, label: 'Description' },
];

const defaultColumnFilter: ColumnFilter = {
  operator: 'Contains',
  value: '',
};

const getProductColumnValue = (item: Product, field: ColumnField) => {
  if (field === 'productType') return item.product_type ?? '';
  if (field === 'active') return item.active ? 'Yes' : 'No';
  return item[field] ?? '';
};

const doesValueMatchColumnFilter = (rawValue: string, filter: ColumnFilter) => {
  const value = rawValue.trim().toLowerCase();
  const filterValue = filter.value.trim().toLowerCase();

  if (filter.operator === 'Blank') return value.length === 0;
  if (filter.operator === 'Not blank') return value.length > 0;
  if (!filterValue) return true;

  switch (filter.operator) {
    case 'Contains':
      return value.includes(filterValue);
    case 'Does not contain':
      return !value.includes(filterValue);
    case 'Equals':
      return value === filterValue;
    case 'Does not equal':
      return value !== filterValue;
    case 'Begins with':
      return value.startsWith(filterValue);
    case 'Ends with':
      return value.endsWith(filterValue);
    default:
      return true;
  }
};

interface ProductFormData {
  id: string | null;
  name: string;
  productType: string;
  manufacturer: string;
  partNo: string;
  cost: string;
  description: string;
  active: boolean;
}

const ProductTable: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [open, setOpen] = useState<boolean>(false);
  const [editing, setEditing] = useState<ProductFormData | null>(null);
  const [activeFilter, setActiveFilter] = useState<string>(filterOptions[0]);
  const [actionAnchorEl, setActionAnchorEl] = useState<HTMLElement | null>(null);
  const [actionRow, setActionRow] = useState<Product | null>(null);
  const [columnsAnchorEl, setColumnsAnchorEl] = useState<HTMLElement | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>(allColumns.map((column) => column.field));
  const [filterMenuField, setFilterMenuField] = useState<ColumnField | null>(null);
  const [columnFilters, setColumnFilters] = useState<Partial<Record<ColumnField, ColumnFilter>>>({});
  const [draftColumnFilter, setDraftColumnFilter] = useState<ColumnFilter>(defaultColumnFilter);
  const [currentPage, setCurrentPage] = useState<number>(1);
  const [pageSize, setPageSize] = useState<number>(10);
  const [productTypes, setProductTypes] = useState<ProductType[]>([]);
  const [loading, setLoading] = useState<boolean>(false);
  const [saving, setSaving] = useState<boolean>(false);
  const actionMenuRef = useRef<HTMLDivElement>(null);
  const columnsMenuRef = useRef<HTMLDivElement>(null);
  const filterMenuRef = useRef<HTMLDivElement>(null);

  const fetchProducts = async () => {
    setLoading(true);
    try {
      const response = await getProducts();
      setProducts(response.data);
    } catch (error) {
      console.error('Error fetching products:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProducts();
    loadProductTypes();
  }, []);

  const loadProductTypes = async () => {
    try {
      const response = await getProductTypes();
      setProductTypes(response.data);
    } catch (error) {
      console.error('Unable to load product types:', error);
    }
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (actionMenuRef.current && !actionMenuRef.current.contains(event.target as Node) && actionAnchorEl && !actionAnchorEl.contains(event.target as Node)) {
        setActionAnchorEl(null);
      }
      if (columnsMenuRef.current && !columnsMenuRef.current.contains(event.target as Node)) {
        setColumnsAnchorEl(null);
      }
      if (filterMenuRef.current && !filterMenuRef.current.contains(event.target as Node)) {
        setFilterMenuField(null);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [actionAnchorEl]);

  const filteredProducts = useMemo(() => {
    return products.filter((item) => {
      const matchesActiveFilter = activeFilter === filterOptions[0] ? item.active : true;
      if (!matchesActiveFilter) return false;

      return allColumns.every((column) => {
        const filter = columnFilters[column.field];
        if (!filter) return true;

        return doesValueMatchColumnFilter(getProductColumnValue(item, column.field), filter);
      });
    });
  }, [activeFilter, columnFilters, products]);

  const totalPages = Math.max(1, Math.ceil(filteredProducts.length / pageSize));
  const startIndex = (currentPage - 1) * pageSize;
  const endIndex = startIndex + pageSize;
  const paginatedProducts = filteredProducts.slice(startIndex, endIndex);

  useEffect(() => {
    if (currentPage > totalPages) {
      setCurrentPage(totalPages);
    }
  }, [currentPage, totalPages]);

  const handleOpen = (item: Product | null = null) => {
    if (item) {
      const typeObj = productTypes.find(pt => pt.display_name === item.product_type);
      setEditing({
        id: item.id,
        name: item.name || '',
        productType: typeObj ? typeObj.id : '',
        manufacturer: item.manufacturer || '',
        partNo: item.partNo || '',
        cost: item.cost || '',
        description: item.description || '',
        active: item.active ?? true,
      });
    } else {
      setEditing(null);
    }
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
    setEditing(null);
  };

  const handleSave = async (product: ProductFormData) => {
    setSaving(true);
    try {
      const typeObj = productTypes.find(pt => pt.id === product.productType);
      const payload = {
        name: product.name,
        product_type: typeObj ? typeObj.display_name : '',
        manufacturer: product.manufacturer,
        part_no: product.partNo,
        cost: product.cost,
        description: product.description,
        active: product.active,
      };

      if (product.id) {
        await updateProduct(product.id, payload);
      } else {
        await createProduct(payload);
      }
      fetchProducts();
      handleClose();
    } catch (error) {
      console.error('Error saving product:', error);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Are you sure you want to delete this product?')) {
      try {
        await deleteProduct(id);
        fetchProducts();
        setActionAnchorEl(null);
      } catch (error) {
        console.error('Error deleting product:', error);
      }
    }
  };

  const handleClearFilters = () => {
    setActiveFilter(filterOptions[0]);
    setColumnFilters({});
    setFilterMenuField(null);
    setDraftColumnFilter(defaultColumnFilter);
    setVisibleColumns(allColumns.map((column) => column.field));
    setCurrentPage(1);
  };

  const handleOpenColumnFilter = (field: ColumnField) => {
    setDraftColumnFilter(columnFilters[field] ?? defaultColumnFilter);
    setFilterMenuField((currentField) => (currentField === field ? null : field));
  };

  const handleApplyColumnFilter = (field: ColumnField) => {
    const needsValue = draftColumnFilter.operator !== 'Blank' && draftColumnFilter.operator !== 'Not blank';
    if (needsValue && !draftColumnFilter.value.trim()) {
      handleResetColumnFilter(field);
      return;
    }

    setColumnFilters((prev) => ({
      ...prev,
      [field]: {
        ...draftColumnFilter,
        value: needsValue ? draftColumnFilter.value : '',
      },
    }));
    setFilterMenuField(null);
    setCurrentPage(1);
  };

  const handleResetColumnFilter = (field: ColumnField) => {
    setColumnFilters((prev) => {
      const next = { ...prev };
      delete next[field];
      return next;
    });
    setDraftColumnFilter(defaultColumnFilter);
    setFilterMenuField(null);
    setCurrentPage(1);
  };

  const actionMenuStyle = actionAnchorEl
    ? {
        top: actionAnchorEl.getBoundingClientRect().bottom + window.scrollY,
        left: actionAnchorEl.getBoundingClientRect().left + window.scrollX,
      }
    : {};

  const renderColumnHeader = (field: ColumnField, label: string) => {
    const hasFilter = Boolean(columnFilters[field]);
    const isValueDisabled = draftColumnFilter.operator === 'Blank' || draftColumnFilter.operator === 'Not blank';

    return (
      <th className="relative px-6 py-3 text-left text-xs font-medium uppercase tracking-wider text-gray-500">
        <div className="flex items-center justify-between gap-2">
          <span>{label}</span>
          <button
            type="button"
            onClick={(event) => {
              event.stopPropagation();
              handleOpenColumnFilter(field);
            }}
            className={`rounded p-1 hover:bg-gray-200 focus:outline-none focus:ring-2 focus:ring-blue-500 ${
              hasFilter ? 'text-blue-600' : 'text-gray-500'
            }`}
            aria-label={`Filter ${label}`}
          >
            <svg className="h-3.5 w-3.5" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
              <path d="M2 3H14M4.5 7H11.5M6.5 11H9.5" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" />
            </svg>
          </button>
        </div>

        {filterMenuField === field && (
          <div ref={filterMenuRef} className="absolute right-2 top-10 z-20 w-48 rounded-md border border-gray-300 bg-white p-3 text-gray-700 shadow-xl">
            <select
              value={draftColumnFilter.operator}
              onChange={(event) => setDraftColumnFilter((prev) => ({ ...prev, operator: event.target.value as ColumnFilterOperator }))}
              className="mb-2 w-full rounded border border-gray-300 bg-white px-2 py-2 text-sm font-normal normal-case tracking-normal text-gray-900 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {columnFilterOptions.map((option) => (
                <option key={option} value={option}>
                  {option}
                </option>
              ))}
            </select>
            <div className="relative">
              <span className="pointer-events-none absolute left-2 top-1/2 -translate-y-1/2 text-gray-400">
                <svg className="h-3.5 w-3.5" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M7 12A5 5 0 1 0 7 2a5 5 0 0 0 0 10ZM10.5 10.5L14 14" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
                </svg>
              </span>
              <input
                value={draftColumnFilter.value}
                onChange={(event) => setDraftColumnFilter((prev) => ({ ...prev, value: event.target.value }))}
                disabled={isValueDisabled}
                placeholder="Filter..."
                className="w-full rounded border border-gray-300 bg-white py-2 pl-7 pr-2 text-sm font-normal normal-case tracking-normal text-gray-900 placeholder:text-gray-400 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-gray-100"
              />
            </div>
            <div className="mt-4 flex justify-end gap-2">
              <button type="button" onClick={() => handleApplyColumnFilter(field)} className="rounded border border-gray-300 bg-white px-3 py-2 text-sm font-normal normal-case tracking-normal text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500">
                Apply
              </button>
              <button type="button" onClick={() => handleResetColumnFilter(field)} className="rounded border border-gray-300 bg-white px-3 py-2 text-sm font-normal normal-case tracking-normal text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500">
                Reset
              </button>
            </div>
          </div>
        )}
      </th>
    );
  };

  return (
    <div className="bg-white rounded-lg shadow-sm p-6">
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 mb-4">
        <div className="flex flex-col md:flex-row md:items-center gap-3">
          <select
            value={activeFilter}
            onChange={(e) => {
              setActiveFilter(e.target.value);
              setCurrentPage(1);
            }}
            className="w-full md:w-64 rounded-md border border-gray-300 bg-white px-3 py-2 text-sm focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            {filterOptions.map((option) => (
              <option key={option} value={option}>
                {option}
              </option>
            ))}
          </select>
          <button
            onClick={() => handleOpen()}
            className="rounded-md bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            New
          </button>
        </div>

        <div className="flex flex-wrap items-center gap-2">
          <button
            onClick={handleClearFilters}
            className="rounded-md border border-gray-300 bg-white px-4 py-2 text-sm text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            Clear All Filters
          </button>
          <div className="relative">
            <button
              onClick={(e) => setColumnsAnchorEl(e.currentTarget)}
              className="rounded-md border border-gray-300 bg-white px-4 py-2 text-sm text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              ▶ Select Columns
            </button>
            {columnsAnchorEl && (
              <div
                ref={columnsMenuRef}
                className="absolute right-0 z-10 mt-1 w-56 rounded-md border border-gray-300 bg-white p-2 shadow-lg"
              >
                {allColumns.map((column) => (
                  <label key={column.field} className="flex cursor-pointer items-center gap-2 rounded-sm px-2 py-1 hover:bg-gray-100">
                    <input
                      type="checkbox"
                      checked={visibleColumns.includes(column.field)}
                      onChange={() => {
                        setVisibleColumns((prev) =>
                          prev.includes(column.field)
                            ? prev.filter((value) => value !== column.field)
                            : [...prev, column.field]
                        );
                      }}
                      className="h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                    />
                    <span className="text-sm text-gray-700">{column.label}</span>
                  </label>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {loading && (
        <div className="flex justify-center items-center py-8">
          <span className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-blue-600"></span>
        </div>
      )}
      <div className="overflow-x-auto">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="w-14 px-6 py-3 text-left text-xs font-medium uppercase tracking-wider text-gray-500"></th>
              {visibleColumns.includes('name') && renderColumnHeader('name', 'Name')}
              {visibleColumns.includes('productType') && renderColumnHeader('productType', 'Product Type')}
              {visibleColumns.includes('manufacturer') && renderColumnHeader('manufacturer', 'Manufacturer')}
              {visibleColumns.includes('partNo') && renderColumnHeader('partNo', 'Part No')}
              {visibleColumns.includes('cost') && renderColumnHeader('cost', 'Cost')}
              {visibleColumns.includes('active') && renderColumnHeader('active', 'Active')}
              {visibleColumns.includes('description') && renderColumnHeader('description', 'Description')}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200 bg-white">
            {paginatedProducts.map((item) => (
              <tr key={item.id} className="hover:bg-gray-50">
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                  <button
                    onClick={(event) => {
                      event.stopPropagation();
                      setActionRow(item);
                      setActionAnchorEl(event.currentTarget);
                    }}
                    className="text-gray-400 hover:text-gray-600"
                    aria-label="Actions"
                  >
                    <span style={{ display: 'inline-block', lineHeight: 0 }}>
                      <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <rect y="4" width="20" height="2" rx="1" fill="currentColor"/>
                        <rect y="9" width="20" height="2" rx="1" fill="currentColor"/>
                        <rect y="14" width="20" height="2" rx="1" fill="currentColor"/>
                      </svg>
                    </span>
                  </button>
                </td>
                {visibleColumns.includes('name') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.name}</td>}
                {visibleColumns.includes('productType') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.product_type}</td>}
                {visibleColumns.includes('manufacturer') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.manufacturer}</td>}
                {visibleColumns.includes('partNo') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.partNo}</td>}
                {visibleColumns.includes('cost') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.cost}</td>}
                {visibleColumns.includes('active') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.active ? 'Yes' : 'No'}</td>}
                {visibleColumns.includes('description') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.description}</td>}
              </tr>
            ))}
            {paginatedProducts.length === 0 && (
              <tr>
                <td colSpan={visibleColumns.length + 1} className="px-6 py-8 text-center text-sm text-gray-500">
                  No products found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="mt-6 flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
        <div className="flex items-center gap-2 text-sm text-gray-700">
          <span>Page Size:</span>
          <select
            value={pageSize}
            onChange={(e) => {
              setPageSize(Number(e.target.value));
              setCurrentPage(1);
            }}
            className="rounded-md border border-gray-300 bg-white px-3 py-1 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value={10}>10</option>
            <option value={25}>25</option>
            <option value={50}>50</option>
          </select>
        </div>

        <div className="flex items-center gap-4 text-sm text-gray-700">
          <span>
            {filteredProducts.length === 0 ? '0 to 0 of 0' : `${startIndex + 1} to ${Math.min(endIndex, filteredProducts.length)} of ${filteredProducts.length}`}
          </span>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setCurrentPage((page) => Math.max(1, page - 1))}
              disabled={currentPage === 1}
              className="rounded-md border border-gray-300 px-3 py-1 text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50"
            >
              ← Prev
            </button>
            <span>Page {currentPage} of {totalPages}</span>
            <button
              onClick={() => setCurrentPage((page) => Math.min(totalPages, page + 1))}
              disabled={currentPage === totalPages}
              className="rounded-md border border-gray-300 px-3 py-1 text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50"
            >
              Next →
            </button>
          </div>
        </div>
      </div>

      {actionAnchorEl && (
        <div
          ref={actionMenuRef}
          className="fixed z-10 w-40 rounded-md border border-gray-300 bg-white shadow-lg"
          style={actionMenuStyle}
        >
          <button
            onClick={() => {
              if (actionRow) handleOpen(actionRow);
              setActionAnchorEl(null);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-gray-700 hover:bg-gray-100"
          >
            Edit
          </button>
          <button
            onClick={() => {
              if (actionRow) handleDelete(actionRow.id);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-gray-700 hover:bg-gray-100"
          >
            Delete
          </button>
        </div>
      )}

      {open && (
        <div className="fixed inset-0 z-50 overflow-y-auto">
          <div className="flex min-h-screen items-center justify-center p-4 text-center">
            <div className="fixed inset-0 bg-gray-500 opacity-50" aria-hidden="true" onClick={handleClose}></div>
            <div className="z-10 w-full max-w-3xl transform overflow-hidden rounded-2xl bg-white p-6 shadow-xl transition-all">
              <div className="mb-4 flex items-center justify-between">
                <h3 className="text-xl font-semibold text-gray-900">
                  {editing ? 'Edit Asset Product' : 'Add Asset Product'}
                </h3>
                <button onClick={handleClose} className="rounded-full bg-gray-100 p-2 text-gray-600 hover:bg-gray-200">
                  ×
                </button>
              </div>
              <ProductForm
                editing={editing}
                onSave={handleSave}
                onClose={handleClose}
                productTypes={productTypes.map(pt => ({ label: pt.display_name, value: pt.id }))}
                saving={saving}
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ProductTable;
